stylesheet:
QWidget {
    background: #111a14;
    color: #c8e0d0;
    font-family: "JetBrains Sans", "Segoe UI Variable", "Segoe UI", "Arial", "Noto Sans", sans-serif;
    font-size: 10pt;
}
#WindowShell {
    background: transparent;
}
QStackedWidget, QStackedWidget > QWidget, QWidget#PagesShell, QStackedWidget#PagesStack {
    background: transparent;
}
QWidget[class="pageRoot"], QWidget[class="pageCanvas"] {
    background: transparent;
}
QLabel {
    background: transparent;
}
#RootFrame {
    background: #142018;
    border: 1px solid #24362a;
    border-radius: 16px;
}
#TitleBar {
    background: #142018;
    border: none;
    border-top-left-radius: 16px;
    border-top-right-radius: 16px;
}
#Sidebar {
    background: #142018;
    border-bottom-left-radius: 16px;
}
#Content {
    background: transparent;
    border: none;
}
#ContentSurface {
    background: qlineargradient(x1:0, y1:1, x2:1, y2:0, stop:0 #111a14, stop:0.62 #142018, stop:1 #182a20);
    border-top: 1px solid #24362a;
    border-left: 1px solid #24362a;
    border-top-left-radius: 18px;
    border-top-right-radius: 0px;
    border-bottom-left-radius: 0px;
    border-bottom-right-radius: 16px;
}
QDialog#AppDialogWindow {
    background: transparent;
    border: none;
}
#DialogRoot {
    background: #16261c;
    border: 1px solid #2a4030;
    border-radius: 12px;
}
#DialogTitleBar {
    background: transparent;
    border: none;
    border-top-left-radius: 12px;
    border-top-right-radius: 12px;
}
#DialogBody {
    background: transparent;
}
#SettingsScroll, #SettingsCanvas, #SettingsScroll QWidget#qt_scrollarea_viewport {
    background: transparent;
    border: none;
}
QFrame[class="settingsSection"] {
    background: #16261c;
    border: 1px solid #2a4030;
    border-radius: 14px;
}
#LoadingOverlay {
    background: rgba(17, 26, 20, 0.6);
}
#LoadingCard {
    background: #16261c;
    border: 1px solid #3a5a44;
    border-radius: 16px;
}
QFrame[class="card"] {
    background: qlineargradient(x1:0, y1:1, x2:1, y2:0, stop:0 #142018, stop:0.68 #16261c, stop:1 #1a2e24);
    border: 1px solid #24362a;
    border-radius: 16px;
}
QFrame[class="modHero"] {
    background: qlineargradient(x1:0, y1:0, x2:1, y2:1, stop:0 #182a20, stop:1 #142018);
    border: 1px solid #2e4a3a;
    border-radius: 16px;
}
QFrame[class="modCard"] {
    background: #16261c;
    border: 1px solid #2a4030;
    border-radius: 16px;
}
QFrame#NotificationsPopup {
    background: #16261c;
    border: 1px solid #2e4a3a;
    border-radius: 14px;
}
QFrame[class="notificationCard"] {
    background: #1a2e24;
    border: 1px solid #2e4a3a;
    border-radius: 12px;
}
QScrollArea#NotificationsScroll, QWidget#NotificationsCanvas {
    background: transparent;
    border: none;
}
QFrame[class="modIconWrap"] {
    background: #1e3628;
    border: 1px solid #3a5a44;
    border-radius: 16px;
}
QLabel[class="title"] {
    font-size: 13pt;
    font-weight: 700;
    color: #e0f0e8;
}
#DashboardTitle {
    padding: 0px;
    margin: 0px;
}
#DashboardPowerBlock {
    background: transparent;
}
QLabel[class="muted"] {
    color: #90b0a0;
}
QLabel[class="modHint"] {
    color: #a0c0b0;
}
QLabel[class="modState"] {
    color: #e0f0e8;
    background: #1e3628;
    border: 1px solid #3a5a44;
    border-radius: 12px;
    padding: 6px 12px;
    font-weight: 600;
}
QLabel[class="modState"][state="enabled"] {
    background: rgba(60, 160, 100, 0.2);
    border: 1px solid #60b080;
    color: #b8f0d0;
}
QLabel[class="modState"][state="installed"] {
    background: rgba(80, 140, 100, 0.16);
    border: 1px solid #608870;
    color: #c0e0d0;
}
QLabel[class="modState"][state="not installed"] {
    background: rgba(100, 130, 110, 0.08);
    border: 1px solid #4a6a58;
    color: #a0c0b0;
}
QLabel[class="modMeta"] {
    color: #90b0a0;
    background: #18261c;
    border: 1px solid #2a4030;
    border-radius: 12px;
    padding: 6px 12px;
}
#ModsSummaryChip, #ModsEnabledChip {
    border-radius: 11px;
}
#ModStateBadge, #ModMetaChip {
    border-radius: 12px;
}
QLabel[class="modBody"] {
    color: #c8e0d0;
    line-height: 1.3em;
}
#ModsScroll, #ModsCanvas, #ComponentsScroll, #ComponentsCanvas {
    background: transparent;
    border: none;
}
QToolButton[class="nav"] {
    min-width: 46px;
    min-height: 46px;
    max-width: 46px;
    max-height: 46px;
    border-radius: 12px;
    border: 1px solid transparent;
    background: transparent;
}
QToolButton[class="nav"]:hover {
    background: #1e3628;
    border: 1px solid #3a5a44;
}
QToolButton[class="nav"]:checked {
    background: #2a4a38;
    border: 1px solid #5a8a6e;
}
QToolButton[class="window"] {
    min-width: 26px;
    min-height: 26px;
    max-width: 26px;
    max-height: 26px;
    border-radius: 12px;
    border: none;
    background: transparent;
    padding: 0px;
    margin: 0px;
}
QToolButton[class="window"][role="close"]:hover {
    background: rgba(80, 150, 100, 0.5);
}
QPushButton {
    background: #1e3628;
    border: 1px solid #3a5a44;
    border-radius: 10px;
    padding: 8px 12px;
}
#LogsFilesShell {
    background: #142018;
    border: 1px solid #24362a;
    border-radius: 16px;
}
QTabBar::tab {
    background: #111a14;
    border: 1px solid #2e4a3a;
    border-radius: 8px;
    padding: 6px 16px;
    margin-right: 4px;
    color: #a0c0b0;
}
QTabBar::tab:selected {
    background: #4a9a6e;
    border-color: #6aba8e;
    color: #ffffff;
}
QTabBar::tab:hover:!selected {
    background: #1e3628;
}
QPushButton[class="settingsSegment"] {
    background: #111a14;
    border: 1px solid #2e4a3a;
    color: #a0c0b0;
}
QPushButton[class="settingsSegment"]:checked {
    background: #4a9a6e;
    color: #ffffff;
}
QToolButton[class="power"] {
    background: qlineargradient(x1:0, y1:0, x2:0, y2:1, stop:0 #5aaa7e, stop:0.48 #4a9a6e, stop:1 #3a7a5a);
    border: 2px solid #6aba8e;
}
QToolButton[class="power"][state="off"] {
    background: qlineargradient(x1:0, y1:0, x2:0, y2:1, stop:0 #2a4a38, stop:0.55 #1e3628, stop:1 #16261c);
    border: 2px solid #3a5a44;
}
QLineEdit, QComboBox, QTextEdit, QTableWidget {
    background: #111a14;
    border: 1px solid #2e4a3a;
    selection-background-color: #2a4a38;
}
QCheckBox::indicator {
    border: 1px solid #5a7a68;
    background: transparent;
}
QCheckBox::indicator:checked {
    border: 1px solid #6aba8e;
    background: #4a9a6e;
}
QListWidget {
    background: #111a14;
    border: 1px solid #2e4a3a;
}
QListWidget::item {
    background: #16261c;
    border: 1px solid #2a4030;
}
QListWidget::item:selected {
    background: #2a4a38;
    border: 1px solid #4a9a6e;
}
QHeaderView::section {
    background: #1e3628;
    color: #c8e0d0;
}
QMenu {
    background: #16261c;
    border: 1px solid #2e4a3a;
}
QMenu::item:selected {
    background: #2a4a38;
}
